// --- Extract Inputs ---
const input = $input.first().json;

// --- Validate Basic Structure ---
if (!input || Object.keys(input).length === 0) {
  return [{
    json: {
      error: true,
      success: false,
      message: '❌ No input data found.'
    }
  }];
}

// --- Extract Data from Nested Structure ---
const agentData = input.agentData || {};
const messageData = input.messageData || {};

// Extract agent information
const agentId = agentData.agentId || null;
const agentName = agentData.agentName || null;
const agentPhone = agentData.agentPhoneNumber || null;
const userId = agentData.userId || messageData.userId || null;

// Extract message information
const message = (messageData.body || '').trim().toLowerCase();
const senderName = messageData.senderName || null;
const timestamp = messageData.timestamp || null;
const conversationId = messageData.conversationId || null;

// Extract meeting data (if exists in input)
const hasPendingMeeting = !!input.hasPendingMeeting;
const meetingId = input.meetingId || null;
const title = (input.title || '').trim();
const dateTime = (input.dateTime || '').trim();
const purpose = (input.purpose || '').trim();
const location = (input.location || 'Virtual').trim();
const meetingStatus = (input.meetingStatus || '').trim();

const errors = [];

// --- Validate Required Fields ---
if (!agentId) errors.push('Agent ID is required.');
if (!userId) errors.push('User ID is required.');
if (!senderName) errors.push('Sender name is required.');
if (!conversationId) errors.push('Conversation ID is required.');

// --- Validate Response Message ---
if (!message) {
  errors.push('Response message is required.');
}

// --- Optional: Validate Meeting Fields (only if hasPendingMeeting is true) ---
if (hasPendingMeeting) {
  if (!meetingId) errors.push('Meeting ID is required for pending meeting.');
  if (!title) errors.push('Meeting title is required.');
  if (!dateTime) errors.push('Meeting date and time required.');
  if (!purpose) errors.push('Meeting purpose is required.');
}

// --- Return Validation Errors Early ---
if (errors.length > 0) {
  return [{
    json: {
      error: true,
      success: false,
      message: `❌ Validation failed:\n${errors.join('\n')}`,
      errors
    }
  }];
}

// --- Define Enhanced Response Categories ---
const confirmKeywords = [
  'ok', 'yes', 'yeah', 'yep', 'sure', 'confirm', 'confirmed',
  'schedule', 'scheduled', 'done', 'agreed', 'agree', 'fine',
  'perfect', 'accept', 'accepted', 'approve', 'approved',
  'good', 'great', 'sounds good', 'looks good', 'alright'
];

const rejectKeywords = [
  'no', 'nope', 'not', 'cant', "can't", 'cannot', 'unable',
  'reschedule', 'change', 'unavailable', 'busy', 'decline',
  'declined', 'reject', 'rejected', 'cancel', 'cancelled',
  'sorry', 'unfortunately', 'won\'t', 'wont'
];

const rescheduleKeywords = [
  'reschedule', 'change', 'another time', 'different time',
  'later', 'postpone', 'move', 'adjust'
];

// --- Determine Response Type with Priority ---
let responseType = 'unknown';
let confidence = 'low';

// Check for reschedule first (higher priority)
if (rescheduleKeywords.some(k => message.includes(k))) {
  responseType = 'reschedule_requested';
  confidence = 'high';
}
// Then check for rejection
else if (rejectKeywords.some(k => message.includes(k))) {
  responseType = 'rejected';
  confidence = 'high';
}
// Finally check for confirmation
else if (confirmKeywords.some(k => message.includes(k))) {
  responseType = 'confirmed';
  confidence = 'high';
}
// If message is very short and ambiguous
else if (message.length <= 3) {
  confidence = 'very_low';
}

// --- Extract contact phone from conversationId (WhatsApp format) ---
const contactPhone = conversationId ? conversationId.replace('@s.whatsapp.net', '') : null;

// --- Construct Validated Output ---
return [{
  json: {
    // Agent Info
    agentId,
    agentName,
    agentPhone,
    userId,

    // Contact Info
    contactName: senderName,
    contactPhone,
    conversationId,

    // Meeting Info (if exists)
    hasPendingMeeting,
    meetingId,
    title,
    dateTime,
    purpose,
    location,
    meetingStatus,

    // Message Info
    originalMessage: messageData.body,
    normalizedMessage: message,
    messageTimestamp: timestamp,

    // Response Analysis
    responseType,
    confidence,

    // Metadata
    primaryCategory: input.primaryCategory || null,
    timestamp: new Date().toISOString(),
    success: true,
    error: false
  }
}];

return [{
  json: {
    success: false,
    message: '❌ No pending meeting found for this contact.'
  }
}];

const meeting = $('Find Pending Meeting').first().json;
const responseData = $('Validate & Classify Response1').first().json;
const agentId = $('Meeting Found?').first().json.agentId || null; // ✅ Extract agentId

// --- Validate Inputs ---
if (!meeting || !meeting.id) {
