    reason: responseData.reason || responseData.message || null,
    timestamp: responseData.timestamp || new Date().toISOString(),
    success: true
  }
}];

const data = $('Merge Meeting & Response Data').first().json;

const schedulerMessage = `✅ *Meeting Confirmed!*\n\n${data.contactName} has confirmed the meeting:\n\n📅 **${data.title}**\n🕐 ${data.dateTime}\n📍 ${data.location}\n\nThe meeting is now scheduled. If you want to reschedule it just let me know?`;

const contactMessage = `✅ *Meeting Confirmed*\n\nThank you for confirming! Your meeting is now scheduled:\n\n📅 **${data.title}**\n🕐 ${data.dateTime}\n📍 ${data.location}\n\nWe'll send you a reminder before the meeting.`;

return [{
  json: {
    schedulerPhone: data.schedulerPhone,
    schedulerMessage: schedulerMessage,
    contactPhone: data.contactPhone,
    contactMessage: contactMessage,
    meetingId: data.meetingId,
    contactName: data.contactName,
    agentId: $('Validate & Classify Response1').first().json.agentId || null // ✅ Include agentId
  }
}];

const data = $('Format Confirmation Messages').first().json;

return [{
  json: {
    success: true,
    message: `✅ Meeting confirmed by ${data.contactName}!`,
    details: {
      meetingId: data.meetingId,
      status: 'scheduled',
      contactName: data.contactName,
      notificationsSent: true
    }
  }
}];

const data = $('Merge Meeting & Response Data').first().json;

const schedulerMessage = `❌ **Meeting Declined**\n\n${data.contactName} has declined the meeting:\n\n📅 **${data.title}**\n🕐 ${data.dateTime}\n📍 ${data.location}\n\n**Reason:** ${data.reason}\n\nThe meeting has been cancelled. Please reschedule if needed.`;

const contactMessage = `✅ **Response Received**\n\nThank you for your response. We've notified the scheduler about your unavailability.\n\nThey may reach out to reschedule the meeting.`;

return [{
  json: {
    schedulerPhone: data.schedulerPhone,
    schedulerMessage: schedulerMessage,
    contactPhone: data.contactPhone,
    contactMessage: contactMessage,
    meetingId: data.meetingId,
    contactName: data.contactName,
    reason: data.reason,
    agentId: data.agentId || null // ✅ Include agentId
  }
}];

const data = $('Format Rejection Messages').first().json;

return [{
  json: {
    success: true,
    message: `❌ Meeting declined by ${data.contactName} and removed from database.`,
    details: {
      meetingId: data.meetingId,
      status: 'cancelled_and_deleted',
      contactName: data.contactName,
      reason: data.reason,
      notificationsSent: true
    }
  }
}];

